sp_widget.client_script:
function PublicStatusController($scope, $location, spUtil) {
  var c = this;
  c.searched = false;
  c.isLoggedUser = false;

  var urlParams = $location.search();
  c.showSuccessBanner = (urlParams.success === 'true');

  c.fetchRecords = function() {
    if (!c.searchName) {
      c.error = "Full Name is required to search.";
      return;
    }
    c.error = null;

    c.data.searchName = c.searchName;
    c.data.searchEmail = c.searchEmail;

    c.server.update().then(function() {
      c.searched = true;
    });
  };

  // NATIVE PORTAL SESSION CAPTURE: Listens to the platform broadcast event
  $scope.$on('sp.user.profile.loaded', function(evt, user) {
    if (user && user.userName && user.userName !== 'guest') {
      initSessionUser(user.userName, user.name);
    }
  });

  // FALLBACK SESSIONS: Synchronous window properties check
  var sessionUser = window.NOW.user || (window.g_user ? { name: g_user.userName, displayName: g_user.getDisplayName() } : null);
  if (sessionUser && sessionUser.name && sessionUser.name !== 'guest') {
    initSessionUser(sessionUser.name, sessionUser.displayName || sessionUser.name);
  } else if (urlParams.name) {
    // URL Parameter Fallback
    c.searchName = decodeURIComponent(urlParams.name);
    c.searchEmail = urlParams.email ? decodeURIComponent(urlParams.email) : '';
    c.fetchRecords();
  }

  // Helper function to bundle variables and execute the background data request
  function initSessionUser(username, displayName) {
    if (c.isLoggedUser) return; // Prevent double execution

    c.isLoggedUser = true;
    c.searchEmail = username; 
    c.searchName = displayName;

    c.data.searchName = c.searchName;
    c.data.searchEmail = c.searchEmail;

    c.server.update().then(function() {
      c.searched = true;
    });
  }
}

sp_widget.script:
(function() {
    data.requests = [];
    data.isLoggedUser = false;

    var searchName = "";
    var searchEmail = "";
    var isGuestUser = (gs.getUserName() == 'guest');

    if (input && input.searchName) {
        searchName = input.searchName;
        searchEmail = input.searchEmail;
    } else if (!isGuestUser) {
        var currentUser = gs.getUser();

        // BULLETPROOF: Pull the email straight from the User ID (user_name) field 
        // since your self-registration enforces email-as-username!
        searchEmail = gs.getUserName(); 
        searchName = currentUser.getDisplayName(); 

        // TEST FALLBACK OVERRIDE FOR ADMIN
        if (searchName === 'System Administrator') {
            searchName = 'public'; 
            searchEmail = 'publictestcitizen@gmail.com';
        }
    }

    // 2. Execute standard GlideRecord search
    if (searchName || searchEmail) {
        if (!input || !input.searchName) {
            data.isLoggedUser = true;
        }

        var gr = new GlideRecord('x_1834272_emergenc_disaster_assistance_request');
        var qc = gr.addQuery('u_citizen_email', searchEmail); 

        if (searchName) {
            qc.addOrCondition('u_citizen_name', searchName);
            qc.addOrCondition('u_citizen_name', searchName.toLowerCase());
            qc.addOrCondition('u_citizen_name', searchName.toUpperCase());

            // Handle variations with or without spaces and mixed casing
            var exactWords = searchName.split(' ');
            if (exactWords.length > 1) {
                var capitalizedName = exactWords.map(function(word) {
                    return word.charAt(0).toUpperCase() + word.slice(1);
                }).join(' ');
                qc.addOrCondition('u_citizen_name', capitalizedName);
            }
        }

        gr.orderByDesc('sys_created_on');
        gr.query();

        while (gr.next()) {
            data.requests.push({
                number: gr.getValue('number'),
                assistance_type: gr.getDisplayValue('u_assistance_type'),
                status: gr.getDisplayValue('u_booking_status'),
                group: gr.getDisplayValue('assignment_group')
            });
        }
    }
})();
